mapper.select:
SELECT e.evaluation_id, e.project_id, p.project_name, e.lot_id, l.lot_code, l.lot_name, e.opening_id, e.status, e.evaluation_mode, e.start_time, e.finalize_time, e.final_summary, e.rollback_reason, e.version, e.create_time, e.update_time FROM t_bid_evaluation e INNER JOIN t_bid_project p ON p.project_id = e.project_id INNER JOIN t_bid_lot l ON l.lot_id = e.lot_id
e.deleted_flag = #{queryForm.deletedFlag} AND p.deleted_flag = 0 AND l.deleted_flag = 0
AND ( p.project_name LIKE CONCAT('%', #{queryForm.keyword}, '%') OR l.lot_name LIKE CONCAT('%', #{queryForm.keyword}, '%') OR l.lot_code LIKE CONCAT('%', #{queryForm.keyword}, '%') OR e.final_summary LIKE CONCAT('%', #{queryForm.keyword}, '%') )
AND e.project_id = #{queryForm.projectId}
AND e.lot_id = #{queryForm.lotId}
AND e.opening_id = #{queryForm.openingId}
AND e.status = #{queryForm.status}
ORDER BY e.create_time DESC, e.evaluation_id DESC
